// tool changes a file, the agent records the file's pre-edit content here, keyed
// to the current user turn; a frontend can then rewind the workspace (and, via the
// controller, the conversation) to an earlier turn.
//
// It is deliberately git-free (like Claude Code's rewind): snapshots live beside
// the session, never touch the user's git, and work in a non-git directory. Only
// edit-tool changes are tracked — bash side effects are not (a shell command's
// targets can't be known in advance), which is why the capture hook only fires for
// tools that can Preview their change.
package checkpoint

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"gaeaW/internal/diff"
)

// FileSnap is one file's state at the moment it was first touched in a turn.
// Content == nil means the file did not exist then, so a restore deletes it.
type FileSnap struct {
	Path    string  `json:"path"`
","tool":"bash"}}

{"ok":true,"success":true,"code":"ok","data":{"result":"// Package learning implements cross-session error pattern learning.
// It extracts recurring failure modes from tool execution results,
// stores them in .gaeaW/learned-patterns.toml, and injects
// actionable guidance into the system prompt at startup.
//
// The goal is to make gaeaW "smarter" over time: common mistakes
// (e.g. editing without first reading the file) are flagged before
// the model repeats them.
package learning

import (
	"crypto/sha256"
	"fmt"
	"sort"
	"strings"
	"time"
)

// Pattern is one recurring failure mode the system has observed across sessions.
// It records the tool, the error signature, what the model did to recover,
// and how often it has occurred.
type Pattern struct {
	Sig            string `toml:"sig"`             // SHA256(content hash), dedup key
	Tool           string `toml:"tool"`            // tool name, e.g. "edit_file"
	ErrorKind      string `toml:"error_kind"`      // normalized error class
	ErrorSnippet   string `toml:"error_snippet"`   // first 80 chars of the error message
	RecoveryAction string `toml:"recovery_action"` // what fixed it, e.g. "read file before edit"
	Count          int    `toml:"count"`           // occurrences across all sessions
	LastSeen       string `toml:"last_seen"`       // ISO 8601 date
	Skipped        bool   `toml:"skipped"`         // user has dismissed this pattern
","tool":"bash"}}

{"ok":true,"success":true,"code":"ok","data":{"result":"// Package diff computes a line-level diff between two versions of a file and
// renders it as a unified diff, with added/removed line counts. It is a pure,
// dependency-free leaf package: the writer tools use it to preview a pending
// change (the new content a write_file / edit_file / multi_edit would produce)
// without touching disk, so a front-end can show an approval card or a
// changed-files panel before the call runs.
//
// The line diff uses Myers' O(ND) algorithm — the same shortest-edit-script
// approach git uses — so the hunks read the way a developer expects rather than
// a naive longest-common-subsequence walk.
package diff

import (
	"strings"

	"gaeaW/internal/strutil"
)

// Kind classifies what a change does to a file's existence, so a UI can label
// it ("new file", "modified", "deleted") without diffing to find out.
type Kind string

const (
	// Create is a write to a path that did not previously exist.
	Create Kind = "create"
	// Modify edits or overwrites an existing file.
	Modify Kind = "modify"
	// Delete empties an existing file to nothing.
	Delete Kind = "delete"
)
