 13→// rebuildTodoState reconstructs the canonical task list from a transcript: the
 14→// latest successful todo_write is the base, then every complete_step after it
 15→// advances an item. Deterministic from persisted messages, so it survives a
 16→// fresh load or a rewind.
 17→// (Design adopted from DeepSeek-Reasonix-V1.12)
 18→func (a *AgentRunner) rebuildTodoState(msgs []provider.Message) {
 19→	successful := successfulToolCallIDs(msgs)
 20→	var todos []evidence.TodoItem
 21→	baseIdx := -1
 22→	for i, msg := range msgs {
 23→		for _, tc := range msg.ToolCalls {
 24→			if tc.Name != "todo_write" || !successful[tc.ID] {
 25→				continue
 26→			}
 27→			rec := evidence.ReceiptFromToolCall(tc.Name, json.RawMessage(tc.Arguments), true, true)
 28→			// A successful empty todo_write is an explicit clear.
 29→			todos = append([]evidence.TodoItem(nil), rec.Todos...)
 30→			baseIdx = i
 31→		}
 32→	}
 33→	if baseIdx < 0 {
 34→		a.setTodoState(nil)
 35→		return
 36→	}
 37→	for i := baseIdx; i < len(msgs); i++ {
 38→		for _, tc := range msgs[i].ToolCalls {
 39→			if tc.Name != "complete_step" || !successful[tc.ID] {
 40→				continue
 41→			}
 42→			rec := evidence.ReceiptFromToolCall(tc.Name, json.RawMessage(tc.Arguments), true, true)
 43→			if m, ok := evidence.MatchStep(rec.Step, todos); ok && canonicalTodoStatus(todos[m.Index-1].Status) != "completed" {
 44→				todos[m.Index-1].Status = "completed"
 45→				promoteNextPendingTodo(todos)
 46→			}
 47→		}
 48→	}
 49→	a.setTodoState(todos)
 50→}
 51→
 52→func (a *AgentRunner) setTodoState(todos []evidence.TodoItem) {
 53→	a.todoMu.Lock()
 54→	a.todoState = append([]evidence.TodoItem(nil), todos...)
 55→	a.todoMu.Unlock()
 56→}
 57→
 58→// CanonicalTodoState returns a copy of the host-reconstructed task list.
 59→func (a *AgentRunner) CanonicalTodoState() []evidence.TodoItem {
 60→	a.todoMu.Lock()
 61→	defer a.todoMu.Unlock()
 62→	return append([]evidence.TodoItem(nil), a.todoState...)
 63→}
 64→
 65→func (a *AgentRunner) incompleteCanonicalTodos() ([]evidence.TodoStepMatch, bool) {
 66→	a.todoMu.Lock()
