 74→// advanceCanonicalTodo flips the canonical todo matching a signed-off step to
 75→// completed (promoting the next pending item to in_progress) and emits a
 76→// synthetic todo_write so the task panel reflects it without the model
 77→// re-sending the whole list.
 78→func (a *AgentRunner) advanceCanonicalTodo(step string) {
 79→	a.todoMu.Lock()
 80→	if len(a.todoState) == 0 {
 81→		a.todoMu.Unlock()
 82→		return
 83→	}
 84→	m, ok := evidence.MatchStep(step, a.todoState)
 85→	if !ok || canonicalTodoStatus(a.todoState[m.Index-1].Status) == "completed" {
 86→		a.todoMu.Unlock()
 87→		return
 88→	}
 89→	a.todoState[m.Index-1].Status = "completed"
 90→	promoteNextPendingTodo(a.todoState)
 91→	snapshot := append([]evidence.TodoItem(nil), a.todoState...)
 92→	a.todoMu.Unlock()
 93→	a.recordTodoState(snapshot)
 94→	a.emitTodoState(snapshot, m.Index)
 95→}
