110→// emitTodoState emits synthetic ToolDispatch and ToolResult events for the
111→// host-advanced todo list so the UI reflects it without model re-sending.
112→func (a *AgentRunner) emitTodoState(todos []evidence.TodoItem, itemIndex int) {
113→	args, err := json.Marshal(map[string]any{"todos": todos})
114→	if err != nil {
